   336→// GET /api/ai-health/daily-breakdown — per-module daily token breakdown from DB
   337→app.get('/api/ai-health/daily-breakdown', requireAdmin, async (req, res) => {
   338→  try {
   339→    const pool = require('./lib/db');
   340→    const date = req.query.date || new Date().toISOString().substring(0, 10);
   341→    const result = await pool.query(
   342→      `SELECT module,
   343→              COUNT(*) as call_count,
   344→              COALESCE(SUM(total_tokens), 0) as total_tokens,
   345→              COALESCE(SUM(cost_estimate), 0) as total_cost,
   346→              COUNT(*) FILTER (WHERE success = false) as failures
   347→       FROM ai_call_log
   348→       WHERE created_at >= $1::date AND created_at < ($1::date + interval '1 day')
   349→       GROUP BY module
   350→       ORDER BY total_tokens DESC`,
   351→      [date]
   352→    );
   353→
   354→    // Calculate totals for percentage
   355→    const totalTokens = result.rows.reduce((s, r) => s + parseInt(r.total_tokens), 0);
   356→    const dailyBudget = 100000; // 100K daily budget
   357→
   358→    const breakdown = result.rows.map(r => ({
   359→      module: r.module,
   360→      call_count: parseInt(r.call_count),
   361→      total_tokens: parseInt(r.total_tokens),
   362→      total_cost: Math.round(parseFloat(r.total_cost) * 10000) / 10000,
   363→      failures: parseInt(r.failures),
   364→      pct_of_daily: totalTokens > 0 ? Math.round((parseInt(r.total_tokens) / totalTokens) * 1000) / 10 : 0,
   365→      pct_of_budget: Math.round((parseInt(r.total_tokens) / dailyBudget) * 1000) / 10,
   366→    }));
   367→
   368→    res.json({
   369→      date,
   370→      total_tokens: totalTokens,
   371→      total_calls: result.rows.reduce((s, r) => s + parseInt(r.call_count), 0),
   372→      daily_budget: dailyBudget,
   373→      budget_used_pct: Math.round((totalTokens / dailyBudget) * 1000) / 10,
   374→      modules: breakdown,
   375→    });
   376→  } catch (err) {
   377→    // Fallback to in-memory if DB table doesn't exist yet
   378→    if (err.message.includes('does not exist')) {
   379→      const aiCallLogger = require('./lib/ai-call-logger');
   380→      const modules = aiCallLogger.getModuleBreakdown();
   381→      const totalTokens = Object.values(modules).reduce((s, m) => s + m.totalTokens, 0);
   382→      res.json({
   383→        date: new Date().toISOString().substring(0, 10),
   384→        total_tokens: totalTokens,
   385→        total_calls: Object.values(modules).reduce((s, m) => s + m.calls, 0),
   386→        daily_budget: 100000,
   387→        budget_used_pct: Math.round((totalTokens / 100000) * 1000) / 10,
   388→        modules: Object.entries(modules).map(([mod, m]) => ({
   389→          module: mod,
   390→          call_count: m.calls,
   391→          total_tokens: m.totalTokens,
   392→          total_cost: m.cost,
   393→          failures: m.failures,
   394→          pct_of_daily: totalTokens > 0 ? Math.round((m.totalTokens / totalTokens) * 1000) / 10 : 0,
   395→          pct_of_budget: Math.round((m.totalTokens / 100000) * 1000) / 10,
   396→        })),
   397→      });
   398→    } else {
   399→      res.status(500).json({ error: 'Failed to get daily breakdown', message: err.message });
   400→    }
   401→  }
   402→});
