   481→app.post('/api/ai-health/prompts', requireAdmin, async (req, res) => {
   482→  try {
   483→    const { slug, name, module, feature, description, systemPrompt, userTemplate, temperature, maxTokens, model, changeNote } = req.body;
   484→    if (!slug || !name || !module) {
   485→      return res.status(400).json({ error: 'slug, name, and module are required' });
   486→    }
   487→
   488→    // Upsert prompt
   489→    const upsertResult = await pool.query(
   490→      `INSERT INTO ai_prompts (slug, name, module, feature, description, model)
   491→       VALUES ($1, $2, $3, $4, $5, $6)
   492→       ON CONFLICT (slug) DO UPDATE SET
   493→         name = EXCLUDED.name, module = EXCLUDED.module, feature = EXCLUDED.feature,
   494→         description = EXCLUDED.description, model = EXCLUDED.model,
   495→         current_version = ai_prompts.current_version + 1,
   496→         updated_at = NOW()
   497→       RETURNING *`,
   498→      [slug, name, module, feature || null, description || null, model || null]
   499→    );
   500→    const prompt = upsertResult.rows[0];
   501→
   502→    // Create version entry
   503→    await pool.query(
   504→      `INSERT INTO ai_prompt_versions (prompt_id, version, system_prompt, user_template, temperature, max_tokens, model, change_note)
   505→       VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
   506→      [prompt.id, prompt.current_version, systemPrompt || null, userTemplate || null,
   507→       temperature || 0.7, maxTokens || 8192, model || null, changeNote || 'Initial version']
   508→    );
   509→
   510→    res.json({ prompt, message: `Version ${prompt.current_version} created` });
   511→  } catch (err) {
